  ('disabled-0a2fc18c-moex-00104', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-113-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '3年前1萬元的水果牌行動電話，今年同樣1萬元可買到同品牌但功能更 強大的行動電話。有關以消費者物價指數（CPI）來衡量生活成本的敘述， 下列何者正確？', '["CPI可以精確捕捉商品品質的提升，因此可反映品質的變化", "CPI會高估今年購買行動電話所花費的生活成本", "CPI會高估3年前購買行動電話所花費的生活成本", "人們也可不換行動電話，因此CPI與反映生活成本無關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "85be7467d750", "answer_pdf_sha1": "6fb4e390116a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "408", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
