  ('disabled-0a2fc18c-moex-00110', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-113-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '若一國的物品與服務之出口與進口各為 1,500 億美元與 1,200 億美元、利 息收入淨額為負 20 億美元、國外移轉所得淨額為零、對外投資 500 億美 元、以及外人投資為400億美元，則該國的經常帳餘額為何？', '["出超180億美元", "出超280億美元", "出超320億美元", "入超380億美元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "85be7467d750", "answer_pdf_sha1": "6fb4e390116a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "408", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
